// Code generated by selo gen --lang rust. DO NOT EDIT.

use crate::mod11::{self, CheckDigit, Rule, SeloError};

const DV: CheckDigit = CheckDigit { weights: &[2, 3, 4, 5, 6, 7, 8, 9], rule: Rule::ElevenMinus, remainder_to0: &[], multiply_by10: false, encode_x_at: 10, encode_zero_at: 11 };

pub const UFS: &[&str] = &["SP", "RJ"];

/// Strip formatting and return (base_digits, check) or None.
fn parse(value: &str) -> Option<(Vec<i32>, i32)> {
    let mut cleaned: Vec<u8> = Vec::new();
    for &ch in value.as_bytes() {
        if ch.is_ascii_digit() || ch == b'X' || ch == b'x' {
            cleaned.push(ch);
        }
    }
    if cleaned.len() != 9 {
        return None;
    }
    let last = cleaned[8];
    let check = if last == b'X' || last == b'x' {
        10
    } else if last == b'0' {
        11
    } else if (b'1'..=b'9').contains(&last) {
        (last - b'0') as i32
    } else {
        return None;
    };
    let mut base: Vec<i32> = Vec::with_capacity(8);
    for &c in &cleaned[0..8] {
        if !c.is_ascii_digit() {
            return None;
        }
        base.push((c - b'0') as i32);
    }
    Some((base, check))
}

/// Validate value as an RG for the given UF (SP/RJ only).
pub fn validate_rg_for_uf(value: &str, uf: &str) -> bool {
    if !UFS.contains(&uf) {
        return false;
    }
    match parse(value) {
        Some((base, check)) => {
            mod11::compute_digit(mod11::weighted_sum(&base, DV.weights, false), &DV) == check
        }
        None => false,
    }
}

/// Validate value under any implemented UF (first match wins).
pub fn validate_rg(value: &str) -> bool {
    UFS.iter().any(|uf| validate_rg_for_uf(value, uf))
}

/// Render an RG as XX.XXX.XXX-C (check char normalized).
pub fn format_rg(value: &str) -> Result<String, SeloError> {
    let (base, check) = match parse(value) {
        Some(p) => p,
        None => return Err(SeloError::InvalidFormat),
    };
    let check_char = mod11::encode_digit(check, &DV);
    let d: String = base.iter().map(|n| n.to_string()).collect();
    Ok(format!("{}.{}.{}-{}", &d[0..2], &d[2..5], &d[5..8], check_char))
}

/// Return a valid SP-style RG in masked form (XX.XXX.XXX-C).
pub fn generate_rg() -> String {
    let mut base: Vec<i32> = Vec::with_capacity(8);
    for _ in 0..8 {
        base.push(mod11::rand_int(9) as i32);
    }
    let dv = mod11::compute_digit(mod11::weighted_sum(&base, DV.weights, false), &DV);
    let check_char = mod11::encode_digit(dv, &DV);
    let d: String = base.iter().map(|n| n.to_string()).collect();
    format!("{}.{}.{}-{}", &d[0..2], &d[2..5], &d[5..8], check_char)
}

#[cfg(test)]
mod tests {
    use super::*;

    fn vector() -> serde_json::Value {
        let p = concat!(env!("CARGO_MANIFEST_DIR"), "/vectors/rg.json");
        let s = std::fs::read_to_string(p).expect("read vector");
        serde_json::from_str(&s).expect("parse vector")
    }

    #[test]
    fn validate_cases() {
        for case in vector()["validate"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let valid = case["valid"].as_bool().unwrap();
            assert_eq!(valid, validate_rg(input), "validate {}", input);
        }
    }

    #[test]
    fn format_cases() {
        for case in vector()["format"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let is_error = case
                .get("error")
                .and_then(|e| e.as_str())
                .map(|e| !e.is_empty())
                .unwrap_or(false);
            if is_error {
                assert!(format_rg(input).is_err(), "format expected err {}", input);
            } else {
                let want = case["output"].as_str().unwrap();
                assert_eq!(want, format_rg(input).unwrap(), "format {}", input);
            }
        }
    }

    #[test]
    fn generate_round_trip() {
        for _ in 0..100 {
            let v = generate_rg();
            assert!(validate_rg(&v), "generate produced invalid: {}", v);
        }
    }
}
